begin;

insert into public.hechos (id, numero, ordinal, capitulo_id, resumen, texto_completo, texto_completo_html, titulo_corto, nota_abogado)
select id, numero, ordinal, capitulo_id, resumen, texto_completo, texto_completo_html, titulo_corto, nota_abogado
from jsonb_to_recordset($hechos$[{"id":"hecho-59","numero":59,"ordinal":"QUINCUAGESIMONOVENO","capitulo_id":"cap-16","resumen":"Pedro desarrollo, de manera independiente y fuera del alcance de los aportes de la sociedad descritos en el Hecho Decimosegundo, una aplicacion educativa de preguntas y respuestas para examenes de residencia orientada a estudiantes de ParetoMed. En l...","texto_completo":"**HECHO QUINCUAGESIMONOVENO.** Pedro desarrollo, de manera independiente y fuera del alcance de los aportes de la sociedad descritos en el Hecho Decimosegundo, una aplicacion educativa de preguntas y respuestas para examenes de residencia orientada a estudiantes de ParetoMed. En la reunion del 2 de junio de 2025, Pedro presento formalmente la aplicacion a Oscar, describiendo sus funcionalidades (modos de preguntas, simulacros semanales, repeticion espaciada, gamificacion con ligas e insignias). En dicha reunion, Oscar *\"expreso su preferencia por la opcion de comprar la aplicacion\"* (01:17:10 de la grabacion), reconociendo asi que la herramienta era propiedad de Pedro y que debia adquirirla. Se discutieron abiertamente tres modelos de negocio: venta, suscripcion o sociedad (01:16:16). Oscar evaluo el prototipo con estudiantes piloto, quienes respondieron favorablemente. Sin embargo, apenas 41 dias despues, Oscar cambio radicalmente de posicion y pretendio que la herramienta fuese propiedad de la sociedad sin reconocimiento adicional alguno, argumentando que Pedro la habia desarrollado en calidad de socio y que por tanto le pertenecia a ParetoMed. Esta pretension fue expresamente rechazada por Pedro, quien reclamo el derecho a licenciarla o explotarla de manera independiente. El 13 de julio de 2025, Oscar declaro en audios de WhatsApp: *\"tu eres socio, no es que vas a sacar tu aplicacion propia... tenemos el acuerdo de que lo que desarrolles es para ParetoMed porque tu eres socio\"* (PTT-20250713-WA0007). En otro audio del mismo bloque, Oscar admitio ademas: *\"tu no estabas trabajando en vainas de examenes de residencia hasta que comenzaste a trabajar conmigo que yo te abria el espacio y te ofreci la sociedad\"* (PTT-20250713-WA0009), y remato: *\"tu lo desarrollaste siendo socio de ParetoMed... yo creo que ahi no hay cabida, no hay duda sobre cual es el proposito de esa aplicacion\"*. Estas declaraciones constituyen un reconocimiento inequivoco de la sociedad de hecho apenas un mes antes de la ruptura: Oscar no solo llamaba socio a Pedro, sino que le exigia obligaciones fiduciarias propias de un socio y admitia que le habia ofrecido la sociedad desde el inicio. Paradojicamente, al invocar los deberes societarios de Pedro para reclamar la herramienta, Oscar confirmo que el vinculo entre las partes era una sociedad, no una prestacion de servicios. La negativa de Pedro a ceder la herramienta sin compensacion y la perspectiva de que Pedro la explotara independientemente fue el detonante que precipito la ruptura definitiva. **[P-05, P-02, P-50, P-34]**\n\n### B. Oscar reconocio aportes metodologicos de Pedro","texto_completo_html":"<p><strong>HECHO QUINCUAGESIMONOVENO.</strong> Pedro desarrollo, de manera independiente y fuera del alcance de los aportes de la sociedad descritos en el Hecho Decimosegundo, una aplicacion educativa de preguntas y respuestas para examenes de residencia orientada a estudiantes de ParetoMed. En la reunion del 2 de junio de 2025, Pedro presento formalmente la aplicacion a Oscar, describiendo sus funcionalidades (modos de preguntas, simulacros semanales, repeticion espaciada, gamificacion con ligas e insignias). En dicha reunion, Oscar <em>&quot;expreso su preferencia por la opcion de comprar la aplicacion&quot;</em> (01:17:10 de la grabacion), reconociendo asi que la herramienta era propiedad de Pedro y que debia adquirirla. Se discutieron abiertamente tres modelos de negocio: venta, suscripcion o sociedad (01:16:16). Oscar evaluo el prototipo con estudiantes piloto, quienes respondieron favorablemente. Sin embargo, apenas 41 dias despues, Oscar cambio radicalmente de posicion y pretendio que la herramienta fuese propiedad de la sociedad sin reconocimiento adicional alguno, argumentando que Pedro la habia desarrollado en calidad de socio y que por tanto le pertenecia a ParetoMed. Esta pretension fue expresamente rechazada por Pedro, quien reclamo el derecho a licenciarla o explotarla de manera independiente. El 13 de julio de 2025, Oscar declaro en audios de WhatsApp: <em>&quot;tu eres socio, no es que vas a sacar tu aplicacion propia... tenemos el acuerdo de que lo que desarrolles es para ParetoMed porque tu eres socio&quot;</em> (PTT-20250713-WA0007). En otro audio del mismo bloque, Oscar admitio ademas: <em>&quot;tu no estabas trabajando en vainas de examenes de residencia hasta que comenzaste a trabajar conmigo que yo te abria el espacio y te ofreci la sociedad&quot;</em> (PTT-20250713-WA0009), y remato: <em>&quot;tu lo desarrollaste siendo socio de ParetoMed... yo creo que ahi no hay cabida, no hay duda sobre cual es el proposito de esa aplicacion&quot;</em>. Estas declaraciones constituyen un reconocimiento inequivoco de la sociedad de hecho apenas un mes antes de la ruptura: Oscar no solo llamaba socio a Pedro, sino que le exigia obligaciones fiduciarias propias de un socio y admitia que le habia ofrecido la sociedad desde el inicio. Paradojicamente, al invocar los deberes societarios de Pedro para reclamar la herramienta, Oscar confirmo que el vinculo entre las partes era una sociedad, no una prestacion de servicios. La negativa de Pedro a ceder la herramienta sin compensacion y la perspectiva de que Pedro la explotara independientemente fue el detonante que precipito la ruptura definitiva. <strong>[P-05, P-02, P-50, P-34]</strong></p>\n<h3>B. Oscar reconocio aportes metodologicos de Pedro</h3>\n","titulo_corto":"\"Eres socio — lo que desarrolles es para ParetoMed\"","nota_abogado":null},{"id":"hecho-60","numero":60,"ordinal":"SEXAGESIMO","capitulo_id":"cap-16","resumen":"En la reunion del 14 de julio de 2025, Oscar Maldonado reconocio expresamente que elementos centrales de la metodologia actual de ParetoMed fueron ideados por Pedro: (a) Oscar *\"confirmo que la idea de los simulacros pre y post estudio, con objetivos...","texto_completo":"**HECHO SEXAGESIMO.** En la reunion del 14 de julio de 2025, Oscar Maldonado reconocio expresamente que elementos centrales de la metodologia actual de ParetoMed fueron ideados por Pedro: (a) Oscar *\"confirmo que la idea de los simulacros pre y post estudio, con objetivos diferentes y la incorporacion de preguntas nuevas al final del simulacro, fue de Pedro Vergara\"*; (b) *\"la idea de enviar mensajes post-simulacro fue de Pedro Vergara\"*; (c) Pedro afirmo que *\"la idea de tener un grupo de WhatsApp para la comunicacion entre estudiantes tambien fue suya\"* sin contradiccion de Oscar; (d) *\"La decision de abordar un modulo por semana surgio de una conversacion entre ambos\"*. En chat del 12 de julio de 2025, Pedro le recordo a Oscar: *\"convertir el simulacro final que tu tenias en un simulacro pre, hacer el post justificado que nacio del grupo de estudio si fueron ideas mias que mejoraron\"* el programa. Oscar respondio: *\"Si reconozco.\"* Adicionalmente, el 11 de abril de 2025, Oscar reconocio: *\"lo de las tutorias ha sido una excelente idea y te he dejado llevarlo como has querido.\"* Estos aportes transformaron la metodologia de ParetoMed de un simple curso pregrabado a un programa estructurado con ciclos de 90 dias, acompanamiento personalizado y evaluacion continua — elementos que constituyen el principal diferenciador comercial del negocio y que justifican el precio de $2.850.000 por estudiante. **[P-34, P-51, P-02]**\n\n### C. Contrato de Cuentas en Participacion predatado","texto_completo_html":"<p><strong>HECHO SEXAGESIMO.</strong> En la reunion del 14 de julio de 2025, Oscar Maldonado reconocio expresamente que elementos centrales de la metodologia actual de ParetoMed fueron ideados por Pedro: (a) Oscar <em>&quot;confirmo que la idea de los simulacros pre y post estudio, con objetivos diferentes y la incorporacion de preguntas nuevas al final del simulacro, fue de Pedro Vergara&quot;</em>; (b) <em>&quot;la idea de enviar mensajes post-simulacro fue de Pedro Vergara&quot;</em>; (c) Pedro afirmo que <em>&quot;la idea de tener un grupo de WhatsApp para la comunicacion entre estudiantes tambien fue suya&quot;</em> sin contradiccion de Oscar; (d) <em>&quot;La decision de abordar un modulo por semana surgio de una conversacion entre ambos&quot;</em>. En chat del 12 de julio de 2025, Pedro le recordo a Oscar: <em>&quot;convertir el simulacro final que tu tenias en un simulacro pre, hacer el post justificado que nacio del grupo de estudio si fueron ideas mias que mejoraron&quot;</em> el programa. Oscar respondio: <em>&quot;Si reconozco.&quot;</em> Adicionalmente, el 11 de abril de 2025, Oscar reconocio: <em>&quot;lo de las tutorias ha sido una excelente idea y te he dejado llevarlo como has querido.&quot;</em> Estos aportes transformaron la metodologia de ParetoMed de un simple curso pregrabado a un programa estructurado con ciclos de 90 dias, acompanamiento personalizado y evaluacion continua — elementos que constituyen el principal diferenciador comercial del negocio y que justifican el precio de $2.850.000 por estudiante. <strong>[P-34, P-51, P-02]</strong></p>\n<h3>C. Contrato de Cuentas en Participacion predatado</h3>\n","titulo_corto":"Oscar reconoce aportes metodológicos de Pedro","nota_abogado":null},{"id":"hecho-61","numero":61,"ordinal":"SEXAGESIMOPRIMERO","capitulo_id":"cap-16","resumen":"El Contrato de Cuentas en Participacion [P-14] fue entregado por Oscar en agosto de 2025, pero su encabezado dice textualmente: *\"El dia 1 de [espacio en blanco] de 2024\"* — con el mes sin completar. Esta predatacion constituye un intento de redefini...","texto_completo":"**HECHO SEXAGESIMOPRIMERO.** El Contrato de Cuentas en Participacion [P-14] fue entregado por Oscar en agosto de 2025, pero su encabezado dice textualmente: *\"El dia 1 de [espacio en blanco] de 2024\"* — con el mes sin completar. Esta predatacion constituye un intento de redefinir retroactivamente la naturaleza de la relacion societaria. En la grabacion del 14 de agosto de 2025, Oscar revelo que este contrato fue disenado por su abogada como una *\"estructura que tiene 90% de seguridad... tributaria\"* para *\"no pagar tanto impuesto\"*. El proposito real del contrato no era reflejar la relacion existente sino crear un instrumento retroactivo que eliminara los derechos de Pedro sobre el patrimonio social. **[P-14, P-01]**\n\n### D. Patron de clausulas anticompetencia en todos los contratos de Oscar","texto_completo_html":"<p><strong>HECHO SEXAGESIMOPRIMERO.</strong> El Contrato de Cuentas en Participacion [P-14] fue entregado por Oscar en agosto de 2025, pero su encabezado dice textualmente: <em>&quot;El dia 1 de [espacio en blanco] de 2024&quot;</em> — con el mes sin completar. Esta predatacion constituye un intento de redefinir retroactivamente la naturaleza de la relacion societaria. En la grabacion del 14 de agosto de 2025, Oscar revelo que este contrato fue disenado por su abogada como una <em>&quot;estructura que tiene 90% de seguridad... tributaria&quot;</em> para <em>&quot;no pagar tanto impuesto&quot;</em>. El proposito real del contrato no era reflejar la relacion existente sino crear un instrumento retroactivo que eliminara los derechos de Pedro sobre el patrimonio social. <strong>[P-14, P-01]</strong></p>\n<h3>D. Patron de clausulas anticompetencia en todos los contratos de Oscar</h3>\n","titulo_corto":"Contrato predatado con mes en blanco","nota_abogado":null},{"id":"hecho-62","numero":62,"ordinal":"SEXAGESIMOSEGUNDO","capitulo_id":"cap-16","resumen":"Todos los contratos propuestos por Oscar incluian clausulas de no competencia dirigidas a restringir la actividad profesional de Pedro: (a) el Acuerdo de Socios propuesto en version SAS incluia una restriccion de **5 anos** que prohibia a Pedro *\"com...","texto_completo":"**HECHO SEXAGESIMOSEGUNDO.** Todos los contratos propuestos por Oscar incluian clausulas de no competencia dirigidas a restringir la actividad profesional de Pedro: (a) el Acuerdo de Socios propuesto en version SAS incluia una restriccion de **5 anos** que prohibia a Pedro *\"comenzar una empresa/emprendimiento/negocio que entre en competencia directa con Paretomed\"* en todo el sector de *\"educacion medica virtual\"* [P-08]; (b) el 13 de enero de 2025, Oscar informo que estaba modificando los estatutos para incluir *\"la clausula de no competencia\"* [P-02]; (c) el Contrato de Transaccion de septiembre 2025 incluia una restriccion de **2 anos** con clausula penal equivalente al 20% de todos los pagos recibidos (~$20.000.000) [P-15]. Las clausulas de no competencia de largo alcance solo se justifican frente a un socio con conocimiento interno del negocio, no frente a un prestador de servicios externo — un contratista de marketing no es un competidor potencial que requiera restriccion por 5 anos. **[P-08, P-15, P-02]**\n\n### E. NETMED S.A.S. — Vehiculo post-ruptura","texto_completo_html":"<p><strong>HECHO SEXAGESIMOSEGUNDO.</strong> Todos los contratos propuestos por Oscar incluian clausulas de no competencia dirigidas a restringir la actividad profesional de Pedro: (a) el Acuerdo de Socios propuesto en version SAS incluia una restriccion de <strong>5 anos</strong> que prohibia a Pedro <em>&quot;comenzar una empresa/emprendimiento/negocio que entre en competencia directa con Paretomed&quot;</em> en todo el sector de <em>&quot;educacion medica virtual&quot;</em> [P-08]; (b) el 13 de enero de 2025, Oscar informo que estaba modificando los estatutos para incluir <em>&quot;la clausula de no competencia&quot;</em> [P-02]; (c) el Contrato de Transaccion de septiembre 2025 incluia una restriccion de <strong>2 anos</strong> con clausula penal equivalente al 20% de todos los pagos recibidos (~$20.000.000) [P-15]. Las clausulas de no competencia de largo alcance solo se justifican frente a un socio con conocimiento interno del negocio, no frente a un prestador de servicios externo — un contratista de marketing no es un competidor potencial que requiera restriccion por 5 anos. <strong>[P-08, P-15, P-02]</strong></p>\n<h3>E. NETMED S.A.S. — Vehiculo post-ruptura</h3>\n","titulo_corto":"Cláusulas anticompetencia de 5 años — solo para socios","nota_abogado":null},{"id":"hecho-63","numero":63,"ordinal":"SEXAGESIMOTERCERO","capitulo_id":"cap-16","resumen":"El 15 de octubre de 2025, Oscar Maldonado constituyo la sociedad **NETMED S.A.S.** (NIT 902.004.012-9, Matricula 926.784) mediante documento privado en Barranquilla, inscrita en la Camara de Comercio el 30 de octubre de 2025. Oscar es propietario del...","texto_completo":"**HECHO SEXAGESIMOTERCERO.** El 15 de octubre de 2025, Oscar Maldonado constituyo la sociedad **NETMED S.A.S.** (NIT 902.004.012-9, Matricula 926.784) mediante documento privado en Barranquilla, inscrita en la Camara de Comercio el 30 de octubre de 2025. Oscar es propietario del 100% de las acciones. La actividad economica registrada es CIIU 6201 (desarrollo de sistemas informaticos). En la grabacion del 14 de agosto de 2025, Oscar admitio el proposito: *\"yo quiero honrar el acuerdo contigo... los abogados y contadores me dijeron... sociedad de hecho con el man no puedes cortarlo... presenteme una forma en que yo pueda mantenerme con el pero tambien pueda crear lo otro... y ahi fue donde seria el contrato de cuentas en participacion\"*. La politica de privacidad actual del sitio web de ParetoMed ya aparece a nombre de NETMED S.A.S. en lugar de Oscar Maldonado persona natural. Sin embargo, en febrero de 2026, la asesora de ventas Adriana continua enviando a interesados el numero de cuenta personal de Oscar Maldonado (no de NETMED) para el pago del programa, lo que evidencia que la transferencia de operaciones a NETMED es formal pero no real. El certificado de Camara de Comercio de NETMED S.A.S. [P-24] revela que la sociedad fue registrada con el correo electronico oscarmaldonado@paretomed.org (dominio del negocio conjunto), en la misma direccion personal de Oscar (CRA 44B #96-67 APTO 606), y que su objeto social incluye expresamente \"plataformas educativas sistematizadas en la web\" a pesar de estar clasificada como empresa de cloud computing (CIIU 6201). El capital pagado es de apenas $10.000.000 COP frente a los ingresos reales del negocio de $709.010.075 COP, y la sociedad reporta ingresos de $0,00. Estos datos confirman que NETMED es un vehiculo nominal creado para canalizar los activos de la sociedad de hecho excluyendo a Pedro. **[P-24, P-01, P-49, P-52]**\n\n### F. Estructura tributaria disenada para evadir","texto_completo_html":"<p><strong>HECHO SEXAGESIMOTERCERO.</strong> El 15 de octubre de 2025, Oscar Maldonado constituyo la sociedad <strong>NETMED S.A.S.</strong> (NIT 902.004.012-9, Matricula 926.784) mediante documento privado en Barranquilla, inscrita en la Camara de Comercio el 30 de octubre de 2025. Oscar es propietario del 100% de las acciones. La actividad economica registrada es CIIU 6201 (desarrollo de sistemas informaticos). En la grabacion del 14 de agosto de 2025, Oscar admitio el proposito: <em>&quot;yo quiero honrar el acuerdo contigo... los abogados y contadores me dijeron... sociedad de hecho con el man no puedes cortarlo... presenteme una forma en que yo pueda mantenerme con el pero tambien pueda crear lo otro... y ahi fue donde seria el contrato de cuentas en participacion&quot;</em>. La politica de privacidad actual del sitio web de ParetoMed ya aparece a nombre de NETMED S.A.S. en lugar de Oscar Maldonado persona natural. Sin embargo, en febrero de 2026, la asesora de ventas Adriana continua enviando a interesados el numero de cuenta personal de Oscar Maldonado (no de NETMED) para el pago del programa, lo que evidencia que la transferencia de operaciones a NETMED es formal pero no real. El certificado de Camara de Comercio de NETMED S.A.S. [P-24] revela que la sociedad fue registrada con el correo electronico <a href=\"mailto:oscarmaldonado@paretomed.org\">oscarmaldonado@paretomed.org</a> (dominio del negocio conjunto), en la misma direccion personal de Oscar (CRA 44B #96-67 APTO 606), y que su objeto social incluye expresamente &quot;plataformas educativas sistematizadas en la web&quot; a pesar de estar clasificada como empresa de cloud computing (CIIU 6201). El capital pagado es de apenas $10.000.000 COP frente a los ingresos reales del negocio de $709.010.075 COP, y la sociedad reporta ingresos de $0,00. Estos datos confirman que NETMED es un vehiculo nominal creado para canalizar los activos de la sociedad de hecho excluyendo a Pedro. <strong>[P-24, P-01, P-49, P-52]</strong></p>\n<h3>F. Estructura tributaria disenada para evadir</h3>\n","titulo_corto":"NETMED: vehículo diseñado para escapar la sociedad","nota_abogado":null},{"id":"hecho-64","numero":64,"ordinal":"SEXAGESIMOCUARTO","capitulo_id":"cap-16","resumen":"El 10 de julio de 2025, Oscar revelo en chat de WhatsApp un plan tributario consistente en crear una LLC en Estados Unidos y una SAS en Colombia que le prestara servicios: *\"la idea es crear una SAS aca en Colombia que le preste servicios a la LLC en...","texto_completo":"**HECHO SEXAGESIMOCUARTO.** El 10 de julio de 2025, Oscar revelo en chat de WhatsApp un plan tributario consistente en crear una LLC en Estados Unidos y una SAS en Colombia que le prestara servicios: *\"la idea es crear una SAS aca en Colombia que le preste servicios a la LLC en EUA. Por la naturaleza de los servicios estaria exento de IVA\"*. En la grabacion del 14 de agosto, Oscar amplio: *\"la vamos a presentar como una empresa de cloud hosting... ya no va a ser una empresa educativa... y ahi no pago tanto impuesto\"*. Esta estructura fue disenada para reducir la carga impositiva del negocio, y el Contrato de Cuentas en Participacion formaba parte de la misma estrategia: *\"creamos alguna estructura que tiene 90% de seguridad... tributaria\"*. El hecho de que Oscar reestructurara el negocio para evadir impuestos mientras dilataba la formalizacion de la sociedad con Pedro evidencia que sus prioridades eran fiscales y no la proteccion de los derechos de su socio. **[P-02, P-01]**","texto_completo_html":"<p><strong>HECHO SEXAGESIMOCUARTO.</strong> El 10 de julio de 2025, Oscar revelo en chat de WhatsApp un plan tributario consistente en crear una LLC en Estados Unidos y una SAS en Colombia que le prestara servicios: <em>&quot;la idea es crear una SAS aca en Colombia que le preste servicios a la LLC en EUA. Por la naturaleza de los servicios estaria exento de IVA&quot;</em>. En la grabacion del 14 de agosto, Oscar amplio: <em>&quot;la vamos a presentar como una empresa de cloud hosting... ya no va a ser una empresa educativa... y ahi no pago tanto impuesto&quot;</em>. Esta estructura fue disenada para reducir la carga impositiva del negocio, y el Contrato de Cuentas en Participacion formaba parte de la misma estrategia: <em>&quot;creamos alguna estructura que tiene 90% de seguridad... tributaria&quot;</em>. El hecho de que Oscar reestructurara el negocio para evadir impuestos mientras dilataba la formalizacion de la sociedad con Pedro evidencia que sus prioridades eran fiscales y no la proteccion de los derechos de su socio. <strong>[P-02, P-01]</strong></p>\n","titulo_corto":"Plan de evasión fiscal — LLC en Estados Unidos","nota_abogado":null}]$hechos$::jsonb)
  as x(id text, numero integer, ordinal text, capitulo_id text, resumen text, texto_completo text, texto_completo_html text, titulo_corto text, nota_abogado text)
on conflict (id) do update set
  numero = excluded.numero,
  ordinal = excluded.ordinal,
  capitulo_id = excluded.capitulo_id,
  resumen = excluded.resumen,
  texto_completo = excluded.texto_completo,
  texto_completo_html = excluded.texto_completo_html,
  titulo_corto = excluded.titulo_corto,
  nota_abogado = excluded.nota_abogado;

delete from public.hecho_pruebas where hecho_id in (select jsonb_array_elements_text($ids$["hecho-59","hecho-60","hecho-61","hecho-62","hecho-63","hecho-64"]$ids$::jsonb));
insert into public.hecho_pruebas (hecho_id, prueba_id)
select hecho_id, prueba_id
from jsonb_to_recordset($rel$[{"hecho_id":"hecho-59","prueba_id":"P-05"},{"hecho_id":"hecho-59","prueba_id":"P-02"},{"hecho_id":"hecho-59","prueba_id":"P-50"},{"hecho_id":"hecho-59","prueba_id":"P-34"},{"hecho_id":"hecho-60","prueba_id":"P-34"},{"hecho_id":"hecho-60","prueba_id":"P-51"},{"hecho_id":"hecho-60","prueba_id":"P-02"},{"hecho_id":"hecho-61","prueba_id":"P-14"},{"hecho_id":"hecho-61","prueba_id":"P-01"},{"hecho_id":"hecho-62","prueba_id":"P-08"},{"hecho_id":"hecho-62","prueba_id":"P-02"},{"hecho_id":"hecho-62","prueba_id":"P-15"},{"hecho_id":"hecho-63","prueba_id":"P-24"},{"hecho_id":"hecho-63","prueba_id":"P-01"},{"hecho_id":"hecho-63","prueba_id":"P-49"},{"hecho_id":"hecho-63","prueba_id":"P-52"},{"hecho_id":"hecho-64","prueba_id":"P-02"},{"hecho_id":"hecho-64","prueba_id":"P-01"}]$rel$::jsonb)
  as x(hecho_id text, prueba_id text)
on conflict do nothing;

delete from public.fragmentos_clave where hecho_id in (select jsonb_array_elements_text($ids$["hecho-59","hecho-60","hecho-61","hecho-62","hecho-63","hecho-64"]$ids$::jsonb));
insert into public.fragmentos_clave (hecho_id, cita, fuente, linea, fecha, autor, relevancia)
select hecho_id, cita, fuente, linea, fecha, autor, relevancia
from jsonb_to_recordset($frag$[{"hecho_id":"hecho-59","cita":"tu eres socio, no es que vas a sacar tu aplicacion propia... tenemos el acuerdo de que lo que desarrolles es para ParetoMed porque tu eres socio","fuente":"transcripciones","linea":8748,"fecha":"13/07/2025","autor":"Oscar Maldonado","relevancia":"CONFESION: Oscar exige deberes de socio sobre la aplicacion educativa independiente de preguntas y respuestas para examenes de residencia, no sobre el Dashboard React del Hecho Decimosegundo — P-50"},{"hecho_id":"hecho-59","cita":"tu no estabas trabajando en vainas de examenes de residencia hasta que comenzaste a trabajar conmigo que yo te abria el espacio y te ofreci la sociedad","fuente":"transcripciones","linea":8757,"fecha":"13/07/2025","autor":"Oscar Maldonado","relevancia":"Admision literal: Oscar reconoce que le abrio el espacio a Pedro y le ofrecio la sociedad antes de reclamar la aplicacion como parte de ParetoMed — P-50"},{"hecho_id":"hecho-59","cita":"tu lo desarrollaste siendo socio de ParetoMed... yo creo que ahi no hay cabida, no hay duda sobre cual es el proposito de esa aplicacion","fuente":"transcripciones","linea":8757,"fecha":"13/07/2025","autor":"Oscar Maldonado","relevancia":"Oscar intenta apropiarse de la aplicacion precisamente porque afirma que Pedro ya la habia desarrollado siendo socio de ParetoMed — P-50"},{"hecho_id":"hecho-60","cita":"Si reconozco.","fuente":"chat-oscar-pedro","linea":29546,"fecha":"12/07/2025","autor":"Oscar Maldonado","relevancia":"Oscar reconoce con dos palabras los aportes metodológicos de Pedro — P-02. Respuesta directa a la lista de aportes presentada por Pedro"},{"hecho_id":"hecho-60","cita":"lo de las tutorias ha sido una excelente idea y te he dejado llevarlo como has querido","fuente":"chat-oscar-pedro","linea":23233,"fecha":"11/04/2025","autor":"Oscar Maldonado","relevancia":"Oscar reconoce ideas de Pedro como mejoras al programa — P-02. 'Dejar llevarlo como has querido' implica autonomía directiva, no seguimiento de instrucciones"},{"hecho_id":"hecho-61","cita":"El dia 1 de [espacio en blanco] de 2024","fuente":"doc-contrato-cp","linea":null,"fecha":"agosto 2025","autor":"Oscar Maldonado","relevancia":"Contrato predatado con mes sin completar — P-14. Evidencia de documento retroactivo: quien redacta un contrato para el presente no deja el mes en blanco"},{"hecho_id":"hecho-61","cita":"estructura que tiene 90% de seguridad... tributaria","fuente":"grabacion-llamada-oscar-250814","linea":42,"fecha":"14/08/2025","autor":"Oscar Maldonado","relevancia":"Oscar revela que el Contrato de Cuentas en Participación fue diseñado por su abogada para beneficio fiscal, no para reflejar la relación real — P-01"},{"hecho_id":"hecho-62","cita":"comenzar una empresa/emprendimiento/negocio que entre en competencia directa con Paretomed","fuente":"doc-acuerdo-sas","linea":128,"fecha":"nov 2024","autor":"Oscar Maldonado","relevancia":"Cláusula de 5 años de no competencia en todo el sector de educación médica virtual — P-08. Las restricciones de 5 años solo se justifican frente a un socio con conocimiento interno total, nunca frente a un contratista de marketing"},{"hecho_id":"hecho-62","cita":"la clausula de no competencia","fuente":"chat-oscar-pedro","linea":18675,"fecha":"13/01/2025","autor":"Oscar Maldonado","relevancia":"Oscar incluye anticompetencia en estatutos de SAS propuesta — P-02. Patrón sistemático: todos los borradores incluyen anticompetencia de largo alcance"},{"hecho_id":"hecho-63","cita":"yo quiero honrar el acuerdo contigo... los abogados y contadores me dijeron... sociedad de hecho con el man no puedes cortarlo... presenteme una forma en que yo pueda mantenerme con el pero tambien pueda crear lo otro","fuente":"grabacion-llamada-oscar-250814","linea":42,"fecha":"14/08/2025","autor":"Oscar Maldonado","relevancia":"Oscar revela en grabación el propósito real de NETMED: un vehículo para escapar de la sociedad con Pedro — P-01. Confesión directa de la estrategia post-ruptura"},{"hecho_id":"hecho-64","cita":"la idea es crear una SAS aca en Colombia que le preste servicios a la LLC en EUA. Por la naturaleza de los servicios estaria exento de IVA","fuente":"chat-oscar-pedro","linea":29392,"fecha":"10/07/2025","autor":"Oscar Maldonado","relevancia":"Oscar revela plan tributario en chat — P-02. La arquitectura fiscal diseñada mientras se dilataba la formalización con Pedro evidencia prioridades opuestas"},{"hecho_id":"hecho-64","cita":"la vamos a presentar como una empresa de cloud hosting... ya no va a ser una empresa educativa... y ahi no pago tanto impuesto","fuente":"grabacion-llamada-oscar-250814","linea":45,"fecha":"14/08/2025","autor":"Oscar Maldonado","relevancia":"Oscar admite en grabación que la reclasificación de ParetoMed como 'cloud hosting' era una estrategia para reducir impuestos — P-01. El demandado usa su propio discurso como evidencia de mala fe"}]$frag$::jsonb)
  as x(hecho_id text, cita text, fuente text, linea text, fecha text, autor text, relevancia text);

